function solve(landStartTime: number[], landDuration: number[], waterStartTime: number[], waterDuration: number[]): number {
    // Helper function to calculate the end time of a ride
    function getEndTime(startTime: number, duration: number): number {
        return startTime + duration;
    }

    // Calculate all possible end times for land and water rides
    const landEndTimes: number[] = [];
    for (let i = 0; i < landStartTime.length; i++) {
        landEndTimes.push(getEndTime(landStartTime[i], landDuration[i]));
    }

    const waterEndTimes: number[] = [];
    for (let j = 0; j < waterStartTime.length; j++) {
        waterEndTimes.push(getEndTime(waterStartTime[j], waterDuration[j]));
    }

    // Check all possible combinations of land and water rides
    let minTime = Infinity;
    for (let i = 0; i < landEndTimes.length; i++) {
        for (let j = 0; j < waterEndTimes.length; j++) {
            // Case 1: Land first, then water
            const landEnd = landEndTimes[i];
            const waterStart = Math.max(landEnd, waterStartTime[j]);
            const waterEnd = getEndTime(waterStart, waterDuration[j]);
            minTime = Math.min(minTime, waterEnd);

            // Case 2: Water first, then land
            const waterEnd = waterEndTimes[j];
            const landStart = Math.max(waterEnd, landStartTime[i]);
            const landEnd2 = getEndTime(landStart, landDuration[i]);
            minTime = Math.min(minTime, landEnd2);
        }
    }

    return minTime;
}

